if (active == 0) {
  wait until ((#Window).armrobot_currentposition > 0)
  active = 1
}
while (active == 1) {
  (#Window).windowcovering_uporopen()
  delay(10 * 60 * 1000)
  (#Window).windowcovering_downorclose()
  delay(10 * 60 * 1000)
}"}

